import React from 'react';
import { Link } from 'react-router-dom';

const HeroSection: React.FC = () => {
    return (
        <div className="bg-cover bg-center h-screen flex flex-col justify-center items-center text-white" style={{ backgroundImage: 'url(/path/to/your/image.jpg)' }}>
            <h1 className="text-5xl font-bold mb-4">Welcome to TravElle</h1>
            <p className="text-lg mb-8">Your travel companion for unforgettable experiences.</p>
            <Link to="/signup" className="bg-pink-500 hover:bg-pink-600 text-white font-bold py-2 px-4 rounded">
                Sign Up
            </Link>
        </div>
    );
};

export default HeroSection;
